local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameObjsPoolCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameObjsPoolCtrl = LxClass("LMatchThreeGameObjsPoolCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local LxUnity = LxUnity
local CS = CS

local typeOfTextMesh = typeof(CS.TextMeshPro)
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)

-----------------------------------------------------------------
function LMatchThreeGameObjsPoolCtrl:LMatchThreeGameObjsPoolCtrl()
    -- 对象列表
    self._objList = {}
end

-- 销毁
function LMatchThreeGameObjsPoolCtrl:OnDestroy()
    LxUnity.Destroy(self._nodeParent)
    self._objList = {}
end

-- 获取节点的父节点
function LMatchThreeGameObjsPoolCtrl:GetNodeParent()
    if not self._nodeParent then
        local root = self:GetMap():GetMapTrans()
        local parent = CS.FindTrans(root, "LayerRoot/LayerNodePool")
        self._nodeParent = LxUnity.NewObject("Pool", parent)
        CS.ShowObject(self._nodeParent, false)
    end
    return self._nodeParent
end

-- 获取节点
function LMatchThreeGameObjsPoolCtrl:GetNode()
    if not self._node then
        local root = self:GetMap():GetMapTrans()
        local trans = CS.FindTrans(root, "LayerRoot/LayerNodePool/Node")
        self._node = trans.gameObject
    end
    return self._node
end

-- 弹出一个对象
function LMatchThreeGameObjsPoolCtrl:PopObj()
    local obj = table.remove(self._objList)
    if not obj then
        obj = self:CreateObj()
    end
    return obj
end

-- 回收一个对象
function LMatchThreeGameObjsPoolCtrl:RecycleObj(obj)
    obj.transform:SetParent(self:GetNodeParent(), false)
    table.insert(self._objList, obj)
end

-- 创建一个对象
function LMatchThreeGameObjsPoolCtrl:CreateObj()
    local obj       = self:GetNode()
    local data      = {}

    data.gameObject = LxUnity.InstantObject(obj)
    data.transform  = data.gameObject.transform
    data.root       = CS.FindTrans(data.transform, "Root")
    data.bg         = CS.FindTrans(data.root, "Bg")
    data.eff        = CS.FindTrans(data.root, "Eff")
    data.icon       = CS.FindTrans(data.root, "Icon")
    data.hpBg       = CS.FindTrans(data.root, "HpBg")
    data.hp         = data.hpBg:GetComponentInChildren(typeOfTextMesh)
    data.iconSprite = data.icon:GetComponent(typeSpriteRenderer)

    local mt      = {}
    mt.__index    = data
    mt.__newindex = function(self, key, value)
        error("此表，只读")
    end

    setmetatable(data, mt)
    return data
end

return LMatchThreeGameObjsPoolCtrl
